from google_adk import Agent, trace
from collections import defaultdict

def detect_circular_delegation(callback, agent):
    traces = trace.get_session_traces(agent.session_id)
    delegation_graph = defaultdict(list)

    for step in traces[-50:]:  # Last 50 steps
        if step.type == 'DELEGATION':
            delegation_graph[step.from_agent].append(step.to_agent)

    # Detect cycles
    visited = set()
    def has_cycle(agent_id):
        if agent_id in visited:
            return True
        visited.add(agent_id)
        for delegate in delegation_graph[agent_id]:
            if has_cycle(delegate):
                return True
        visited.remove(agent_id)
        return False

    recent_agents = {step.from_agent for step in traces[-10:]}
    for agent_id in recent_agents:
        if has_cycle(agent_id):
            raise Exception(f'Circular delegation detected: {agent_id}')

from google_adk import get_workflow

def check_model_consistency(workflow):
    agent_models = {}
    for agent in workflow.agents.values():
        model = agent.llm.model_name
        if model not in agent_models:
            agent_models[model] = []
        agent_models[model].append(agent.name)

    if len(agent_models) > 1:
        error = f'Model inconsistency detected: {agent_models}'
        raise ValueError(error)

    print('✅ All agents use consistent model:', list(agent_models.keys())[0])

