def normalize_tool_response(response):
    if isinstance(response, str):
        return {'content': response, 'type': 'text'}
    elif isinstance(response, dict) and 'content' in response:
        return response
    else:
        return {'content': str(response), 'type': 'unknown', 'error': 'format_mismatch'}

def safe_state_reset(session):
    if session.state.get('corruption_detected', False):
        # Preserve only conversation history
        history = session.state.get('conversation_history', [])
        session.state = {
            'conversation_history': history[-10:],  # Last 10 turns
            'tool_responses': [],
            'delegation_depth': 0,
            'reset_count': session.state.get('reset_count', 0) + 1
        }
